function detectCurrentPage() {
const path = window.location.pathname;
if (path.indexOf('menu') !== -1) return 'menu';
if (path.indexOf('/blog/') !== -1 && path.indexOf('blog.html') === -1) return 'blog-post';
if (path.indexOf('blog') !== -1) return 'blog';
if (path.indexOf('404') !== -1) return '404';
if (path.indexOf('review-qr') !== -1) return 'review-qr';
return 'index';
}
async function loadLayout() {
const page = detectCurrentPage();
const isSubdir = window.location.pathname.indexOf('/blog/') !== -1;
const prefix = isSubdir ? '../' : '';
const navPlaceholder = document.getElementById('nav-placeholder');
if (navPlaceholder) {
try {
const navResponse = await fetch(prefix + 'components/nav.html');
const navHtml = await navResponse.text();
navPlaceholder.outerHTML = navHtml;
if (page === 'index') {
document.querySelectorAll('[data-home-href]').forEach(function(el) {
el.setAttribute('href', el.getAttribute('data-home-href'));
});
}
if (page !== 'index') {
const navbar = document.getElementById('navbar');
if (navbar) navbar.classList.add('scrolled');
}
if (isSubdir) {
document.querySelectorAll('.nav-menu a, .nav-logo, .footer a').forEach(function(el) {
const href = el.getAttribute('href');
if (href && !href.startsWith('http') && !href.startsWith('#') && !href.startsWith('../') && !href.startsWith('tel:') && !href.startsWith('mailto:')) {
el.setAttribute('href', '../' + href);
}
});
}
const activePage = (page === 'blog-post') ? 'blog' : page;
document.querySelectorAll('.nav-link[data-page]').forEach(function(link) {
if (link.getAttribute('data-page') === activePage) {
link.classList.add('active');
}
});
if (page === 'index') {
const homeLink = document.querySelector('.nav-link[data-page="index"]');
if (homeLink) homeLink.classList.add('active');
}
} catch (err) {
console.warn('Failed to load nav:', err);
}
}
const footerPlaceholder = document.getElementById('footer-placeholder');
if (footerPlaceholder) {
try {
const footerFile = (page === 'index') ? 'components/footer.html' : 'components/footer-simple.html';
const footerResponse = await fetch(prefix + footerFile);
const footerHtml = await footerResponse.text();
footerPlaceholder.outerHTML = footerHtml;
} catch (err) {
console.warn('Failed to load footer:', err);
}
}
}
function escapeHtml(str) {
if (typeof str !== 'string') return '';
return str
.replace(/&/g, '&amp;')
.replace(/</g, '&lt;')
.replace(/>/g, '&gt;')
.replace(/"/g, '&quot;')
.replace(/'/g, '&#39;');
}
function t(key, fallback) {
const lang = document.documentElement.lang || 'vi';
if (window.TRANSLATIONS && TRANSLATIONS[lang] && TRANSLATIONS[lang][key]) {
return TRANSLATIONS[lang][key];
}
if (fallback !== undefined) return fallback;
if (window.TRANSLATIONS && TRANSLATIONS.vi && TRANSLATIONS.vi[key]) {
return TRANSLATIONS.vi[key];
}
return key;
}
function formatDateVi(dateStr) {
const parts = dateStr.split('-');
return parts[2] + '/' + parts[1] + '/' + parts[0];
}
function initPreloader() {
const preloader = document.getElementById('preloader');
if (!preloader) return;
let fallbackTimer = setTimeout(() => {
preloader.classList.add('hidden');
}, 3000);
window.addEventListener('load', () => {
clearTimeout(fallbackTimer);
setTimeout(() => preloader.classList.add('hidden'), 600);
});
}
function initModalClose() {
const btn = document.getElementById('closeModalBtn');
const modal = document.getElementById('successModal');
if (btn && modal) {
btn.addEventListener('click', () => {
modal.classList.remove('active');
});
}
}
function showNotification(message, type = 'success') {
const existing = document.querySelector('.toast-notification');
if (existing) existing.remove();
const toast = document.createElement('div');
toast.className = 'toast-notification toast-' + type;
const icon = document.createElement('span');
icon.className = 'toast-icon';
icon.textContent = type === 'success' ? '\u2713' : '\u2717';
const msg = document.createElement('span');
msg.className = 'toast-msg';
msg.textContent = message;
toast.appendChild(icon);
toast.appendChild(msg);
Object.assign(toast.style, {
position: 'fixed',
top: '24px',
right: '24px',
zIndex: '4000',
display: 'flex',
alignItems: 'center',
gap: '12px',
padding: '16px 24px',
borderRadius: '12px',
background: type === 'success' ? '#065F46' : '#991B1B',
color: '#fff',
fontSize: '0.95rem',
fontFamily: 'Inter, sans-serif',
boxShadow: '0 8px 30px rgba(0,0,0,0.25)',
transform: 'translateX(120%)',
transition: 'transform 0.4s cubic-bezier(0.4,0,0.2,1)',
maxWidth: '400px',
});
document.body.appendChild(toast);
requestAnimationFrame(() => { toast.style.transform = 'translateX(0)'; });
setTimeout(() => {
toast.style.transform = 'translateX(120%)';
setTimeout(() => toast.remove(), 400);
}, 4000);
}
function setMinDate() {
const dateInput = document.getElementById('date');
if (dateInput) {
const today = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Ho_Chi_Minh' }));
const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');
dateInput.setAttribute('min', yyyy + '-' + mm + '-' + dd);
}
}
function setCurrentYear() {
const el = document.getElementById('currentYear');
if (el) el.textContent = new Date().getFullYear();
}
function initQRCode() {
const container = document.getElementById('qrCode');
if (!container) return;
const reviewUrl = SITE_CONFIG.social.googleMaps;
if (typeof qrcode !== 'undefined') {
const qr = qrcode(0, 'M');
qr.addData(reviewUrl);
qr.make();
const imgTag = qr.createImgTag(5, 10);
container.innerHTML = imgTag;
const qrImg = container.querySelector('img');
if (qrImg) {
qrImg.style.borderRadius = '8px';
qrImg.alt = 'QR Code đánh giá Google Maps Trạm Dừng Chill';
}
} else {
const fallbackDiv = document.createElement('div');
Object.assign(fallbackDiv.style, { padding: '20px', textAlign: 'center', background: '#f5f5f5', borderRadius: '12px' });
const p = document.createElement('p');
Object.assign(p.style, { fontSize: '0.85rem', color: '#666', marginBottom: '10px' });
p.textContent = 'Quét mã QR hoặc';
const a = document.createElement('a');
a.href = reviewUrl;
a.target = '_blank';
a.rel = 'noopener';
Object.assign(a.style, { color: '#C8572A', fontWeight: '600', textDecoration: 'underline' });
a.textContent = 'Bấm vào đây để đánh giá';
fallbackDiv.appendChild(p);
fallbackDiv.appendChild(a);
container.appendChild(fallbackDiv);
}
}
function generateSchemas() {
const page = detectCurrentPage();
if (page === 'index') {
injectSchema(buildRestaurantSchema());
injectSchema(buildFaqSchema());
injectSchema(buildReviewSchema());
} else if (page === 'blog') {
injectSchema(buildBlogSchema());
} else if (page === 'menu') {
injectSchema(buildMenuSchema());
}
}
function injectSchema(data) {
const script = document.createElement('script');
script.type = 'application/ld+json';
script.textContent = JSON.stringify(data);
document.head.appendChild(script);
}
function buildRestaurantSchema() {
const r = SCHEMA_DATA.restaurant;
return {
'@context': 'https://schema.org',
'@type': 'Restaurant',
'name': r.name,
'alternateName': r.alternateName,
'description': r.description,
'image': r.images,
'url': r.url,
'telephone': r.telephone,
'address': {
'@type': 'PostalAddress',
'streetAddress': r.address.street,
'addressLocality': r.address.locality,
'addressRegion': r.address.region,
'postalCode': r.address.postalCode,
'addressCountry': r.address.country
},
'geo': {
'@type': 'GeoCoordinates',
'latitude': r.geo.latitude,
'longitude': r.geo.longitude
},
'servesCuisine': r.cuisine,
'openingHoursSpecification': {
'@type': 'OpeningHoursSpecification',
'dayOfWeek': ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'],
'opens': r.hours.open,
'closes': r.hours.close
},
'priceRange': r.priceRange,
'currenciesAccepted': r.currenciesAccepted,
'paymentAccepted': r.paymentAccepted,
'acceptsReservations': 'True',
'hasMenu': {
'@type': 'Menu',
'name': 'Menu ' + r.name,
'url': r.url + '/#menu'
},
'aggregateRating': {
'@type': 'AggregateRating',
'ratingValue': r.rating.value,
'reviewCount': r.rating.count,
'bestRating': r.rating.best
},
'amenityFeature': r.amenities.map(function(a) {
return {
'@type': 'LocationFeatureSpecification',
'name': a.name,
'value': a.value
};
}),
'sameAs': r.sameAs
};
}
function buildFaqSchema() {
return {
'@context': 'https://schema.org',
'@type': 'FAQPage',
'mainEntity': SCHEMA_DATA.faq.map(function(item) {
return {
'@type': 'Question',
'name': item.question,
'acceptedAnswer': {
'@type': 'Answer',
'text': item.answer
}
};
})
};
}
function buildReviewSchema() {
const r = SCHEMA_DATA.restaurant;
return {
'@context': 'https://schema.org',
'@type': 'Restaurant',
'@id': r.url + '/#restaurant',
'name': r.name,
'review': SCHEMA_DATA.reviews.map(function(rev) {
return {
'@type': 'Review',
'reviewRating': {
'@type': 'Rating',
'ratingValue': rev.rating,
'bestRating': '5'
},
'author': {
'@type': 'Person',
'name': rev.author
},
'reviewBody': rev.body,
'datePublished': rev.date
};
})
};
}
function buildBlogSchema() {
const r = SCHEMA_DATA.restaurant;
const articles = (typeof BLOG_ARTICLES !== 'undefined') ? BLOG_ARTICLES : [];
return {
'@context': 'https://schema.org',
'@type': 'Blog',
'name': 'Blog ' + r.name,
'description': t('schema.blog.desc', 'Chia sẻ trải nghiệm ăn nướng BBQ, du lịch Đà Lạt'),
'url': r.url + '/blog.html',
'publisher': {
'@type': 'Organization',
'name': r.name,
'url': r.url
},
'blogPost': articles.map(function(a) {
return {
'@type': 'BlogPosting',
'headline': a.title,
'description': a.excerpt.replace(/<[^>]*>/g, ''),
'datePublished': a.date,
'author': {
'@type': 'Organization',
'name': r.name
},
'image': r.url + '/' + a.image
};
})
};
}
function buildMenuSchema() {
const r = SCHEMA_DATA.restaurant;
let sections = [];
if (typeof MENU_CATEGORIES !== 'undefined' && typeof MENU_ITEMS !== 'undefined') {
sections = MENU_CATEGORIES.map(function(cat) {
const items = (MENU_ITEMS[cat.id] || []).map(function(item) {
const menuItem = {
'@type': 'MenuItem',
'name': item.name,
'description': item.name + ' — ' + cat.label + ' tại Trạm Dừng Chill Đà Lạt'
};
if (/^\d/.test(item.price)) {
menuItem.offers = {
'@type': 'Offer',
'price': item.price.replace(/K$/i, '000'),
'priceCurrency': 'VND',
'availability': 'https://schema.org/InStock'
};
}
return menuItem;
});
return {
'@type': 'MenuSection',
'name': cat.label,
'hasMenuItem': items
};
});
}
return {
'@context': 'https://schema.org',
'@type': 'Menu',
'name': 'Thực Đơn ' + r.name,
'description': 'Thực đơn quán nướng BBQ Đà Lạt — Nướng tại bàn, lẩu, hải sản, đồ uống. Giá cập nhật mới nhất.',
'url': r.url + '/menu.html',
'mainEntity': {
'@type': 'Restaurant',
'name': r.name,
'url': r.url,
'telephone': r.telephone,
'address': {
'@type': 'PostalAddress',
'streetAddress': r.address.street,
'addressLocality': r.address.locality,
'addressRegion': r.address.region,
'postalCode': r.address.postalCode,
'addressCountry': r.address.country
},
'openingHoursSpecification': {
'@type': 'OpeningHoursSpecification',
'dayOfWeek': ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'],
'opens': r.hours.open,
'closes': r.hours.close
},
'servesCuisine': r.cuisine
},
'hasMenuSection': sections
};
}
function initNavbar() {
const navbar = document.getElementById('navbar');
const navToggle = document.getElementById('navToggle');
const navMenu = document.getElementById('navMenu');
const navLinks = document.querySelectorAll('.nav-link');
const navOverlay = document.getElementById('navOverlay');
if (!navbar || !navToggle || !navMenu) return;
let scrollY = 0;
function closeMenu() {
navToggle.classList.remove('active');
navToggle.setAttribute('aria-expanded', 'false');
navMenu.classList.remove('open');
if (navOverlay) navOverlay.classList.remove('active');
document.body.classList.remove('menu-open');
document.body.style.top = '';
window.scrollTo(0, scrollY);
}
function openMenu() {
scrollY = window.scrollY;
navToggle.classList.add('active');
navToggle.setAttribute('aria-expanded', 'true');
navMenu.classList.add('open');
if (navOverlay) navOverlay.classList.add('active');
document.body.classList.add('menu-open');
document.body.style.top = `-${scrollY}px`;
}
navToggle.addEventListener('click', () => {
navMenu.classList.contains('open') ? closeMenu() : openMenu();
});
if (navOverlay) {
navOverlay.addEventListener('click', closeMenu);
}
navLinks.forEach(link => {
link.addEventListener('click', closeMenu);
});
}
function initI18n() {
const saved = localStorage.getItem('lang');
let lang;
if (saved) {
lang = saved;
} else {
const browserLang = (navigator.language || navigator.userLanguage || 'vi').toLowerCase();
lang = browserLang.startsWith('en') ? 'en' : 'vi';
}
document.documentElement.lang = lang;
applyTranslations(lang);
setupLangToggle(lang);
}
function applyTranslations(lang) {
if (!window.TRANSLATIONS || !TRANSLATIONS[lang]) return;
const dict = TRANSLATIONS[lang];
const els = document.querySelectorAll('[data-i18n]');
for (let i = 0; i < els.length; i++) {
const key = els[i].getAttribute('data-i18n');
if (dict[key]) {
els[i].innerHTML = dict[key];
}
}
const phEls = document.querySelectorAll('[data-i18n-ph]');
for (let i = 0; i < phEls.length; i++) {
const key = phEls[i].getAttribute('data-i18n-ph');
if (dict[key]) {
phEls[i].placeholder = dict[key];
}
}
}
function setupLangToggle(currentLang) {
const btn = document.getElementById('langToggle');
if (!btn) return;
updateLangButton(btn, currentLang);
btn.addEventListener('click', function () {
const newLang = document.documentElement.lang === 'vi' ? 'en' : 'vi';
document.body.classList.add('lang-transitioning');
setTimeout(function () {
document.documentElement.lang = newLang;
localStorage.setItem('lang', newLang);
applyTranslations(newLang);
updateLangButton(btn, newLang);
setTimeout(function () {
document.body.classList.remove('lang-transitioning');
}, 50);
}, 200);
});
}
function updateLangButton(btn, lang) {
const globe = '<svg class="lang-globe" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>';
if (lang === 'vi') {
btn.innerHTML = globe + '<span class="lang-text">EN</span>';
btn.setAttribute('aria-label', 'Switch to English');
btn.title = 'Switch to English';
} else {
btn.innerHTML = globe + '<span class="lang-text">VI</span>';
btn.setAttribute('aria-label', 'Chuyển sang Tiếng Việt');
btn.title = 'Chuyển sang Tiếng Việt';
}
}
function initScrollProgress() {
const bar = document.getElementById('scrollProgress');
if (!bar) return;
let ticking = false;
function updateProgress() {
const scrollTop = window.scrollY || document.documentElement.scrollTop;
const docHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
const progress = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
bar.style.width = progress + '%';
ticking = false;
}
window.addEventListener('scroll', function () {
if (!ticking) {
requestAnimationFrame(updateProgress);
ticking = true;
}
}, { passive: true });
updateProgress();
}
function initScrollReveal() {
const selectors = [
'.exp-card', '.section-header', '.booking-info',
'.booking-form-wrapper', '.map-wrapper', '.review-wrapper',
'.occasions-banner', '.qr-card'
];
const elements = document.querySelectorAll(selectors.join(', '));
elements.forEach(el => el.classList.add('reveal'));
const gridItems = document.querySelectorAll('.menu-item, .gallery-item');
gridItems.forEach(el => el.classList.add('reveal'));
const observer = new IntersectionObserver((entries) => {
entries.forEach(entry => {
if (entry.isIntersecting) {
const parent = entry.target.parentElement;
const isGridChild = parent && (parent.classList.contains('menu-grid') || parent.classList.contains('gallery-grid'));
const delay = isGridChild ? Array.from(parent.children).indexOf(entry.target) * 40 : 0;
setTimeout(() => {
entry.target.classList.add('visible');
}, delay);
observer.unobserve(entry.target);
}
});
}, {
threshold: 0.08,
rootMargin: '0px 0px -40px 0px'
});
elements.forEach(el => observer.observe(el));
gridItems.forEach(el => observer.observe(el));
}
function initSmoothScroll() {
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
anchor.addEventListener('click', function(e) {
e.preventDefault();
const target = document.querySelector(this.getAttribute('href'));
if (target) {
target.scrollIntoView({ behavior: 'smooth', block: 'start' });
}
});
});
}
function initScrollUI() {
const navbar = document.getElementById('navbar');
const fab = document.getElementById('fabContainer');
const backToTop = document.getElementById('backToTop');
const sections = document.querySelectorAll('section[id]');
let ticking = false;
function onScroll() {
const scrollY = window.scrollY;
if (navbar) navbar.classList.toggle('scrolled', scrollY > 60);
if (fab) fab.classList.toggle('visible', scrollY > 400);
if (backToTop) backToTop.classList.toggle('visible', scrollY > 800);
const offset = scrollY + 120;
sections.forEach(section => {
const top = section.offsetTop;
const height = section.offsetHeight;
const id = section.getAttribute('id');
const link = document.querySelector('.nav-link[href="#' + id + '"]');
if (link) {
link.classList.toggle('active', offset >= top && offset < top + height);
}
});
ticking = false;
}
window.addEventListener('scroll', () => {
if (!ticking) {
requestAnimationFrame(onScroll);
ticking = true;
}
}, { passive: true });
if (backToTop) {
backToTop.addEventListener('click', () => {
window.scrollTo({ top: 0, behavior: 'smooth' });
});
}
onScroll();
const mapEmbed = document.getElementById('mapEmbed');
if (mapEmbed && mapEmbed.dataset.src) {
const mapObserver = new IntersectionObserver(function(entries) {
if (entries[0].isIntersecting) {
const iframe = document.createElement('iframe');
iframe.src = mapEmbed.dataset.src;
iframe.width = '100%';
iframe.height = '100%';
iframe.style.border = '0';
iframe.allowFullscreen = true;
iframe.loading = 'lazy';
iframe.referrerPolicy = 'no-referrer-when-downgrade';
iframe.title = 'Bản đồ Tiệm Nướng Trạm Dừng Chill';
mapEmbed.innerHTML = '';
mapEmbed.appendChild(iframe);
mapObserver.disconnect();
}
}, { rootMargin: '200px' });
mapObserver.observe(mapEmbed);
}
}
